const fs = require('fs');
const path = require('path');

const RAW_FILE = 'response.json';
const OUTPUT_DIR = './output';

const raw = fs.readFileSync(RAW_FILE, 'utf8');
const arrayStart = raw.indexOf('[{"type":"tool_use"');

if (arrayStart === -1) {
  console.error('Could not find tool_calls array');
  process.exit(1);
}

const toolUseMarker = '"name":"write_file"';
let searchPos = arrayStart;
const results = [];

while (true) {
  const markerPos = raw.indexOf(toolUseMarker, searchPos);
  if (markerPos === -1) break;

  let objStart = markerPos;
  while (objStart > 0 && raw[objStart - 1] !== '{') objStart--;

  let depth = 0, inString = false, escape = false, i = objStart, foundEnd = false;
  while (i < raw.length) {
    const c = raw[i];
    if (escape) { escape = false; i++; continue; }
    if (c === '\\') { escape = true; i++; continue; }
    if (c === '"') { inString = !inString; i++; continue; }
    if (!inString) { if (c === '{') depth++; else if (c === '}') { depth--; if (depth === 0) { foundEnd = true; i++; break; } } }
    i++;
  }

  if (!foundEnd) break;

  const toolUseStr = raw.substring(objStart, i);
  searchPos = i;

  const filePathMatch = toolUseStr.match(/"file_path":"([^"]+)"/);
  if (!filePathMatch) continue;
  const filePath = filePathMatch[1];

  const contentMatch = toolUseStr.match(/"content":"([\s\S]*?)"(?=,"language")/);
  if (!contentMatch) continue;

  let rawContent = contentMatch[1];
  rawContent = cleanCurlOutput(rawContent);

  try {
    const content = JSON.parse('"' + rawContent + '"');
    results.push({ file_path: filePath, content, success: true });
  } catch (e) {
    const curlStart = rawContent.indexOf('\r100  133k');
    if (curlStart !== -1) {
      const beforeCorruption = rawContent.substring(0, curlStart);
      try {
        const content = JSON.parse('"' + beforeCorruption + '"');
        results.push({ file_path: filePath, content, success: true });
        continue;
      } catch (e2) {}
    }
    results.push({ file_path: filePath, content: rawContent, success: false, error: e.message });
  }
}

if (fs.existsSync(OUTPUT_DIR)) fs.rmSync(OUTPUT_DIR, { recursive: true, force: true });
fs.mkdirSync(OUTPUT_DIR, { recursive: true });

for (const result of results) {
  const fullPath = path.join(OUTPUT_DIR, result.file_path);
  const dir = path.dirname(fullPath);
  if (!fs.existsSync(dir)) fs.mkdirSync(dir, { recursive: true });
  fs.writeFileSync(fullPath, result.content, 'utf8');
  console.log('Created:', result.file_path);
}

function cleanCurlOutput(content) {
  const curlCorruptionIdx = content.indexOf('\r100  133k');
  if (curlCorruptionIdx === -1) return content;

  const resumePattern = '\\n        <input';
  const resumeIdx = content.indexOf(resumePattern, curlCorruptionIdx);

  if (resumeIdx === -1) return content.substring(0, curlCorruptionIdx);

  const beforeCurl = content.substring(0, curlCorruptionIdx);
  const afterCorruptionResume = content.substring(resumeIdx + resumePattern.length);

  return beforeCurl + 've\\">\\n        <input' + afterCorruptionResume;
}
